import { useCallback } from 'react';
import type { Dispatch, MutableRefObject, SetStateAction } from 'react';
import { getGenerationDropData } from '@/shared/lib/dnd/dragDrop';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { uploadImageToStorage } from '@/shared/lib/media/imageUploader';
import { generateClientThumbnail, uploadImageWithThumbnail } from '@/shared/media/clientThumbnailGenerator';
import { createExternalUploadGeneration } from '@/integrations/supabase/repositories/generationMutationsRepository';
import { generateUUID } from '@/shared/lib/taskCreation/ids';
import { getCompatibleTrackId, updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getTrackIndex } from '@/tools/video-editor/lib/editor-utils';
import {
  getNextClipId,
  inferTrackType,
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type {
  TimelineApplyEdit,
  TimelineInvalidateAssetRegistry,
  TimelinePatchRegistry,
  TimelineRegisterAsset,
  TimelineUploadAsset,
} from '@/tools/video-editor/hooks/timeline-state-types';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';
import type { AssetRegistryEntry, ClipType } from '@/tools/video-editor/types';

export interface UseAssetManagementArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  selectedTrackId: string | null;
  selectedProjectId: string | null;
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
  applyEdit: TimelineApplyEdit;
  patchRegistry: TimelinePatchRegistry;
  registerAsset: TimelineRegisterAsset;
  uploadAsset: TimelineUploadAsset;
  invalidateAssetRegistry: TimelineInvalidateAssetRegistry;
  resolveAssetUrl: (file: string) => Promise<string>;
}

export interface UseAssetManagementResult {
  registerGenerationAsset: (data: ReturnType<typeof getGenerationDropData>) => string | null;
  uploadImageGeneration: (file: File) => Promise<{
    generationId: string;
    variantType: 'image';
    imageUrl: string;
    thumbUrl: string;
    metadata: {
      content_type: string;
      original_filename: string;
    };
  }>;
  handleAssetDrop: (assetKey: string, trackId: string | undefined, time: number, forceNewTrack?: boolean, insertAtTop?: boolean) => void;
}

export interface AssetDropTargetResolution {
  current: TimelineData;
  trackId: string;
}

export interface BuildAssetDropEditResult {
  clipId: string;
  duration: number;
  rows: TimelineData['rows'];
  metaUpdates: Record<string, ClipMeta>;
  clipOrderOverride: TimelineData['clipOrder'];
}

export function resolveAssetDropTarget({
  dataRef,
  assetKind,
  trackId,
  selectedTrackId,
  forceNewTrack = false,
  insertAtTop = false,
}: {
  dataRef: MutableRefObject<TimelineData | null>;
  assetKind: 'audio' | 'visual';
  trackId: string | undefined;
  selectedTrackId: string | null;
  forceNewTrack?: boolean;
  insertAtTop?: boolean;
}): AssetDropTargetResolution | null {
  let current = dataRef.current;
  if (!current) {
    return null;
  }

  let resolvedTrackId = forceNewTrack
    ? null
    : getCompatibleTrackId(current.tracks, trackId, assetKind, selectedTrackId);

  if (!resolvedTrackId) {
    const latest = dataRef.current;
    if (!latest) {
      return null;
    }

    const existingTrackId = forceNewTrack
      ? null
      : getCompatibleTrackId(latest.tracks, trackId, assetKind, selectedTrackId);
    if (existingTrackId) {
      current = latest;
      resolvedTrackId = existingTrackId;
    } else {
      const prefix = assetKind === 'audio' ? 'A' : 'V';
      const nextNumber = getTrackIndex(latest.tracks, prefix) + 1;
      resolvedTrackId = `${prefix}${nextNumber}`;
      const newTrack = {
        id: resolvedTrackId,
        kind: assetKind,
        label: `${prefix}${nextNumber}`,
      };
      current = {
        ...latest,
        tracks: insertAtTop ? [newTrack, ...latest.tracks] : [...latest.tracks, newTrack],
        rows: insertAtTop ? [{ id: resolvedTrackId, actions: [] }, ...latest.rows] : [...latest.rows, { id: resolvedTrackId, actions: [] }],
      };
      dataRef.current = current;
    }
  }

  return resolvedTrackId
    ? { current, trackId: resolvedTrackId }
    : null;
}

export function buildAssetDropEdit({
  current,
  assetKey,
  trackId,
  time,
}: {
  current: TimelineData;
  assetKey: string;
  trackId: string;
  time: number;
}): BuildAssetDropEditResult | null {
  const assetEntry = current.registry.assets[assetKey];
  const assetKind = inferTrackType(assetEntry?.file ?? assetKey);
  const track = current.tracks.find((candidate) => candidate.id === trackId);
  if (!track) {
    return null;
  }

  const clipId = getNextClipId(current.meta);
  const isImage = assetEntry?.type?.startsWith('image');
  const isVideo = assetEntry?.type?.startsWith('video') || (!isImage && assetKind === 'visual' && assetEntry?.duration);
  const isManual = track.fit === 'manual';
  const clipType: ClipType = isImage ? 'hold' : 'media';
  const baseDuration = isVideo
    ? (assetEntry?.duration ?? 5)
    : isImage
      ? 5
      : Math.max(1, assetEntry?.duration ?? 5);

  let clipMeta: ClipMeta;
  let duration: number;

  if (track.kind === 'audio') {
    duration = assetEntry?.duration ?? 10;
    clipMeta = {
      asset: assetKey,
      track: trackId,
      clipType: 'media',
      from: 0,
      to: duration,
      speed: 1,
      volume: 1,
    };
  } else if (isImage) {
    duration = 5;
    clipMeta = {
      asset: assetKey,
      track: trackId,
      clipType,
      hold: duration,
      opacity: 1,
      x: isManual ? 100 : undefined,
      y: isManual ? 100 : undefined,
      width: isManual ? 320 : undefined,
      height: isManual ? 240 : undefined,
    };
  } else {
    duration = baseDuration;
    clipMeta = {
      asset: assetKey,
      track: trackId,
      clipType,
      from: 0,
      to: duration,
      speed: 1,
      volume: 1,
      opacity: 1,
      x: isManual ? 100 : undefined,
      y: isManual ? 100 : undefined,
      width: isManual ? 320 : undefined,
      height: isManual ? 240 : undefined,
    };
  }

  const action: TimelineAction = {
    id: clipId,
    start: time,
    end: time + duration,
    effectId: `effect-${clipId}`,
  };

  return {
    clipId,
    duration,
    rows: current.rows.map((row) => (row.id === trackId ? { ...row, actions: [...row.actions, action] } : row)),
    metaUpdates: { [clipId]: clipMeta },
    clipOrderOverride: updateClipOrder(current.clipOrder, trackId, (ids) => [...ids, clipId]),
  };
}

export function useAssetManagement({
  dataRef,
  selectedTrackId,
  selectedProjectId,
  setSelectedClipId,
  setSelectedTrackId,
  applyEdit,
  patchRegistry,
  registerAsset,
}: UseAssetManagementArgs): UseAssetManagementResult {
  const registerGenerationAsset = useCallback((generationData: ReturnType<typeof getGenerationDropData>) => {
    if (!generationData) {
      return null;
    }

    const mimeType = (() => {
      const metadataContentType = typeof generationData.metadata?.content_type === 'string'
        ? generationData.metadata.content_type
        : null;
      if (metadataContentType?.includes('/')) {
        return metadataContentType;
      }
      if (metadataContentType === 'video' || generationData.variantType === 'video' || /\.(mp4|mov|webm|m4v)$/i.test(generationData.imageUrl)) {
        return 'video/mp4';
      }
      if (metadataContentType === 'audio' || /\.(mp3|wav|aac|m4a)$/i.test(generationData.imageUrl)) {
        return 'audio/mpeg';
      }
      return 'image/png';
    })();

    const assetId = generateUUID();
    const entry: AssetRegistryEntry = {
      file: generationData.imageUrl,
      type: mimeType,
      generationId: generationData.generationId,
      variantId: generationData.variantId,
    };

    patchRegistry(assetId, entry, generationData.imageUrl);
    void registerAsset(assetId, entry).catch((error) => {
      console.error('[video-editor] Failed to persist generation asset:', error);
    });

    return assetId;
  }, [patchRegistry, registerAsset]);

  const uploadImageGeneration = useCallback(async (file: File) => {
    if (!selectedProjectId) {
      throw new Error('External image drop requires a selected project');
    }

    let imageUrl = '';
    let thumbnailUrl = '';

    try {
      const thumbnailResult = await generateClientThumbnail(file, 300, 0.8);
      const uploadResult = await uploadImageWithThumbnail(file, thumbnailResult.thumbnailBlob);
      imageUrl = uploadResult.imageUrl;
      thumbnailUrl = uploadResult.thumbnailUrl;
    } catch (error) {
      normalizeAndPresentError(error, { context: `video-editor:external-drop:${file.name}`, showToast: false });
      imageUrl = await uploadImageToStorage(file, 3);
      thumbnailUrl = imageUrl;
    }

    const generation = await createExternalUploadGeneration({
      imageUrl,
      thumbnailUrl,
      fileType: 'image',
      projectId: selectedProjectId,
      generationParams: {
        prompt: `Uploaded ${file.name}`,
        extra: {
          source: 'external_upload',
          original_filename: file.name,
          file_type: file.type || 'image',
          file_size: file.size,
        },
      },
    });

    return {
      generationId: generation.id,
      variantType: 'image' as const,
      imageUrl,
      thumbUrl: thumbnailUrl,
      metadata: {
        content_type: file.type || 'image',
        original_filename: file.name,
      },
    };
  }, [selectedProjectId]);

  const handleAssetDrop = useCallback((assetKey: string, trackId: string | undefined, time: number, forceNewTrack = false, insertAtTop = false) => {
    const resolvedTarget = resolveAssetDropTarget({
      dataRef,
      assetKind: inferTrackType(dataRef.current?.registry.assets[assetKey]?.file ?? assetKey),
      trackId,
      selectedTrackId,
      forceNewTrack,
      insertAtTop,
    });
    if (!resolvedTarget) {
      return;
    }
    const nextEdit = buildAssetDropEdit({
      current: resolvedTarget.current,
      assetKey,
      trackId: resolvedTarget.trackId,
      time,
    });
    if (!nextEdit) {
      return;
    }
    applyEdit({
      type: 'rows',
      rows: nextEdit.rows,
      metaUpdates: nextEdit.metaUpdates,
      clipOrderOverride: nextEdit.clipOrderOverride,
    });
    setSelectedClipId(nextEdit.clipId);
    setSelectedTrackId(resolvedTarget.trackId);
  }, [applyEdit, dataRef, selectedTrackId, setSelectedClipId, setSelectedTrackId]);

  return {
    registerGenerationAsset,
    uploadImageGeneration,
    handleAssetDrop,
  };
}

import type { DragEvent, MutableRefObject } from 'react';
import type { GenerationDropData } from '@/shared/lib/dnd/dragDrop';
import { getDragType } from '@/shared/lib/dnd/dragDrop';
import { createAutoScroller } from '@/tools/video-editor/lib/auto-scroll';
import { getCompatibleTrackId, updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getTrackIndex } from '@/tools/video-editor/lib/editor-utils';
import { inferDragKind } from '@/tools/video-editor/lib/drop-position';
import { resolveOverlaps } from '@/tools/video-editor/lib/resolve-overlaps';
import {
  createEffectLayerClipMeta,
  getNextClipId,
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type { UseAssetManagementResult } from '@/tools/video-editor/hooks/useAssetManagement';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import type {
  TimelineApplyEdit,
  TimelineInvalidateAssetRegistry,
  TimelinePatchRegistry,
  TimelineUploadAsset,
} from '@/tools/video-editor/hooks/timeline-state-types';
import type { TrackKind } from '@/tools/video-editor/types';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

export type TimelineDropPosition = NonNullable<ReturnType<DragCoordinator['update']>>;

export function isGenerationDragType(dragType: ReturnType<typeof getDragType>) {
  return dragType === 'generation' || dragType === 'generation-multi';
}

export function isVideoGeneration(data: GenerationDropData): boolean {
  const contentType = typeof data.metadata?.content_type === 'string'
    ? data.metadata.content_type
    : null;

  return contentType?.startsWith('video/')
    || data.variantType === 'video'
    || /\.(mp4|mov|webm|m4v)$/i.test(data.imageUrl);
}

export function readPositiveNumber(value: unknown): number | null {
  return typeof value === 'number' && Number.isFinite(value) && value > 0 ? value : null;
}

export function getDroppedGenerationDuration(data: GenerationDropData): number {
  if (!isVideoGeneration(data)) {
    return 5;
  }

  return readPositiveNumber(data.metadata?.duration)
    ?? readPositiveNumber(data.metadata?.duration_seconds)
    ?? readPositiveNumber(data.metadata?.original_duration)
    ?? 5;
}

export function createTrack(
  dataRef: MutableRefObject<TimelineData | null>,
  kind: 'audio' | 'visual',
  insertAtTop: boolean,
  label?: string,
): { trackId: string; insertAtTop: boolean } | null {
  const current = dataRef.current;
  if (!current) {
    return null;
  }

  const prefix = kind === 'audio' ? 'A' : 'V';
  const nextNumber = getTrackIndex(current.tracks, prefix) + 1;
  const trackId = `${prefix}${nextNumber}`;
  const nextTrack = { id: trackId, kind, label: label ?? trackId };
  const nextRow = { id: trackId, actions: [] };

  dataRef.current = {
    ...current,
    tracks: insertAtTop ? [nextTrack, ...current.tracks] : [...current.tracks, nextTrack],
    rows: insertAtTop ? [nextRow, ...current.rows] : [...current.rows, nextRow],
  };

  return { trackId, insertAtTop };
}

export function createTrackAtTop(
  dataRef: MutableRefObject<TimelineData | null>,
  kind: 'audio' | 'visual',
  label?: string,
): { trackId: string; insertAtTop: true } | null {
  const createdTrack = createTrack(dataRef, kind, true, label);
  return createdTrack ? { ...createdTrack, insertAtTop: true } : null;
}

export function createTrackForDrop(
  dataRef: MutableRefObject<TimelineData | null>,
  kind: 'audio' | 'visual',
  insertAtTop: boolean,
  label?: string,
): { trackId: string; insertAtTop: boolean } | null {
  return insertAtTop
    ? createTrackAtTop(dataRef, kind, label)
    : createTrack(dataRef, kind, false, label);
}

export function removeAction(rows: TimelineData['rows'], actionId: string) {
  return rows.map((row) => ({
    ...row,
    actions: row.actions.filter((action) => action.id !== actionId),
  }));
}

export function inferFileDropKind(file: File): TrackKind {
  const extension = file.name.slice(file.name.lastIndexOf('.')).toLowerCase();
  return ['.mp3', '.wav', '.aac', '.m4a'].includes(extension) ? 'audio' : 'visual';
}

export function isImageFile(file: File): boolean {
  const extension = file.name.slice(file.name.lastIndexOf('.')).toLowerCase();
  return file.type.startsWith('image/')
    || ['.png', '.jpg', '.jpeg', '.webp', '.gif', '.bmp', '.avif'].includes(extension);
}

export function handleTextToolDrop({
  dataRef,
  dropPosition,
  insertAtTop,
  handleAddTextAt,
}: {
  dataRef: MutableRefObject<TimelineData | null>;
  dropPosition: TimelineDropPosition;
  insertAtTop: boolean;
  handleAddTextAt?: (trackId: string, time: number) => void;
}): boolean {
  if (!handleAddTextAt || !dataRef.current) {
    return false;
  }

  let targetTrackId = dropPosition.isNewTrack ? undefined : dropPosition.trackId;
  if (!targetTrackId) {
    targetTrackId = createTrackForDrop(dataRef, 'visual', insertAtTop)?.trackId;
  }

  if (!targetTrackId) {
    return true;
  }

  handleAddTextAt(targetTrackId, dropPosition.time);
  return true;
}

export function handleEffectLayerDrop({
  dataRef,
  dropPosition,
  insertAtTop,
  selectedTrackId,
  applyEdit,
}: {
  dataRef: MutableRefObject<TimelineData | null>;
  dropPosition: TimelineDropPosition;
  insertAtTop: boolean;
  selectedTrackId: string | null;
  applyEdit: TimelineApplyEdit;
}): boolean {
  let current = dataRef.current;
  if (!current) {
    return false;
  }

  let targetTrackId = dropPosition.isNewTrack
    ? null
    : getCompatibleTrackId(current.tracks, dropPosition.trackId, 'visual', selectedTrackId);

  if (!targetTrackId) {
    targetTrackId = createTrackForDrop(dataRef, 'visual', insertAtTop)?.trackId ?? null;
    current = dataRef.current;
  }

  if (!targetTrackId || !current) {
    return true;
  }

  const clipId = getNextClipId(current.meta);
  const clipMeta = createEffectLayerClipMeta(targetTrackId);
  const duration = clipMeta.hold ?? 5;
  const action: TimelineAction = {
    id: clipId,
    start: Math.max(0, dropPosition.time),
    end: Math.max(0, dropPosition.time) + duration,
    effectId: `effect-${clipId}`,
  };
  const rowsWithClip = current.rows.map((row) => (
    row.id === targetTrackId
      ? { ...row, actions: [...row.actions, action] }
      : row
  ));
  const { rows: nextRows, metaPatches, adjustments: _adjustments } = resolveOverlaps(
    rowsWithClip,
    targetTrackId,
    clipId,
    current.meta,
  );
  const resolvedAction = nextRows
    .find((row) => row.id === targetTrackId)
    ?.actions.find((candidate) => candidate.id === clipId);
  const nextClipOrder = updateClipOrder(current.clipOrder, targetTrackId, (ids) => [...ids, clipId]);

  applyEdit({
    type: 'rows',
    rows: nextRows,
    metaUpdates: {
      ...metaPatches,
      [clipId]: {
        ...clipMeta,
        hold: resolvedAction ? Math.max(0.05, resolvedAction.end - resolvedAction.start) : clipMeta.hold,
      },
    },
    clipOrderOverride: nextClipOrder,
  });
  return true;
}

export async function handleFileDrop({
  files,
  dataRef,
  pendingOpsRef,
  dropPosition,
  insertAtTop,
  selectedTrackId,
  applyEdit,
  patchRegistry,
  uploadAsset,
  invalidateAssetRegistry,
  resolveAssetUrl,
  registerGenerationAsset,
  uploadImageGeneration,
  dropAsset,
}: {
  files: File[];
  dataRef: MutableRefObject<TimelineData | null>;
  pendingOpsRef: MutableRefObject<number>;
  dropPosition: TimelineDropPosition;
  insertAtTop: boolean;
  selectedTrackId: string | null;
  applyEdit: TimelineApplyEdit;
  patchRegistry: TimelinePatchRegistry;
  uploadAsset: TimelineUploadAsset;
  invalidateAssetRegistry: TimelineInvalidateAssetRegistry;
  resolveAssetUrl: (file: string) => Promise<string>;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  uploadImageGeneration: UseAssetManagementResult['uploadImageGeneration'];
  dropAsset: UseAssetManagementResult['handleAssetDrop'];
}): Promise<boolean> {
  if (!files.length || !dataRef.current) {
    return false;
  }

  const defaultClipDuration = 5;
  let timeOffset = 0;

  for (const file of files) {
    const kind = inferFileDropKind(file);
    let compatibleTrackId = dropPosition.isNewTrack

    let compatibleTrackId = dropPosition.isNewTrack
      ? null
      : getCompatibleTrackId(dataRef.current.tracks, dropPosition.trackId, kind, selectedTrackId);

    if (!compatibleTrackId) {
      compatibleTrackId = createTrackForDrop(dataRef, kind, insertAtTop)?.trackId ?? null;
    }

    if (!compatibleTrackId || !dataRef.current) {
      continue;
    }

    const clipTime = dropPosition.time + timeOffset;
    timeOffset += defaultClipDuration;

    const skeletonId = `uploading-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
    const skeletonMeta: ClipMeta = {
      asset: `uploading:${file.name}`,
      track: compatibleTrackId,
      clipType: kind === 'audio' ? 'media' : 'hold',
      hold: kind === 'audio' ? undefined : defaultClipDuration,
      from: kind === 'audio' ? 0 : undefined,
      to: kind === 'audio' ? defaultClipDuration : undefined,
    };
    const skeletonAction: TimelineAction = {
      id: skeletonId,
      start: clipTime,
      end: clipTime + defaultClipDuration,
      effectId: `effect-${skeletonId}`,
    };

    const nextRows = dataRef.current.rows.map((row) =>
      row.id === compatibleTrackId
        ? { ...row, actions: [...row.actions, skeletonAction] }
        : row,
    );
    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: { [skeletonId]: skeletonMeta },
    }, { save: false });

    pendingOpsRef.current += 1;
    void (async () => {
      try {
        if (isImageFile(file)) {
          const generationData = await uploadImageGeneration(file);
          const current = dataRef.current;
          if (!current) {
            return;
          }

          applyEdit({
            type: 'rows',
            rows: removeAction(current.rows, skeletonId),
            metaDeletes: [skeletonId],
          });
          const assetId = registerGenerationAsset(generationData);
          if (assetId) {
            dropAsset(assetId, compatibleTrackId ?? undefined, clipTime);
          }
          return;
        }

        const result = await uploadAsset(file);
        const sourceUrl = await resolveAssetUrl(result.entry.file);
        patchRegistry(result.assetId, result.entry, sourceUrl);

        const current = dataRef.current;
        if (!current) {
          return;
        }

        applyEdit({
          type: 'rows',
          rows: removeAction(current.rows, skeletonId),
          metaDeletes: [skeletonId],
        });
        dropAsset(result.assetId, compatibleTrackId ?? undefined, clipTime);
        void invalidateAssetRegistry();
      } catch (error) {
        console.error('[drop] Upload failed:', error);
        const current = dataRef.current;
        if (!current) {
          return;
        }

        applyEdit({
          type: 'rows',
          rows: removeAction(current.rows, skeletonId),
          metaDeletes: [skeletonId],
        }, { save: false });
      } finally {
        pendingOpsRef.current -= 1;
      }
    })();
  }

  return true;
}

export function handleMultiGenerationDrop({
  generationItems,
  dataRef,
  dropPosition,
  insertAtTop,
  registerGenerationAsset,
  patchRegistry,
  dropAsset,
}: {
  generationItems: GenerationDropData[];
  dataRef: MutableRefObject<TimelineData | null>;
  dropPosition: TimelineDropPosition;
  insertAtTop: boolean;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  patchRegistry: TimelinePatchRegistry;
  dropAsset: UseAssetManagementResult['handleAssetDrop'];
}): boolean {
  if (!generationItems.length || !dataRef.current) {
    return false;
  }

  let targetTrackId = dropPosition.isNewTrack ? undefined : dropPosition.trackId;
  let forceNewTrack = dropPosition.isNewTrack;
  let timeOffset = 0;

  for (const generationData of generationItems) {
    const trackIdsBeforeDrop = new Set(dataRef.current.tracks.map((track) => track.id));
    const assetId = registerGenerationAsset(generationData);

    if (!assetId) {
      continue;
    }

    if (isVideoGeneration(generationData)) {
      const existingEntry = dataRef.current.registry.assets[assetId];
      if (existingEntry) {
        patchRegistry(assetId, {
          ...existingEntry,
          duration: getDroppedGenerationDuration(generationData),
        }, generationData.imageUrl);
      }
    }

    dropAsset(
      assetId,
      targetTrackId,
      dropPosition.time + timeOffset,
      forceNewTrack,
      forceNewTrack ? insertAtTop : false,
    );

    timeOffset += getDroppedGenerationDuration(generationData);

    if (!forceNewTrack || !dataRef.current) {
      continue;
    }

    const createdTrackId = dataRef.current.tracks.find((track) => !trackIdsBeforeDrop.has(track.id))?.id
      ?? (insertAtTop ? dataRef.current.tracks[0]?.id : dataRef.current.tracks[dataRef.current.tracks.length - 1]?.id);
    if (createdTrackId) {
      targetTrackId = createdTrackId;
    }
    forceNewTrack = false;
  }

  return true;
}

export function handleSingleGenerationDrop({
  generationData,
  dataRef,
  dropPosition,
  insertAtTop,
  registerGenerationAsset,
  dropAsset,
}: {
  generationData: GenerationDropData;
  dataRef: MutableRefObject<TimelineData | null>;
  dropPosition: TimelineDropPosition;
  insertAtTop: boolean;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  dropAsset: UseAssetManagementResult['handleAssetDrop'];
}): boolean {
  if (!dataRef.current) {
    return false;
  }

  const assetId = registerGenerationAsset(generationData);
  if (!assetId) {
    return true;
  }

  dropAsset(
    assetId,
    dropPosition.isNewTrack ? undefined : dropPosition.trackId,
    dropPosition.time,
    dropPosition.isNewTrack,
    insertAtTop,
  );
  return true;

import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { getSupabaseUrl } from '@/integrations/supabase/config/env';
import { storagePaths, getFileExtension, generateUniqueFilename, MEDIA_BUCKET } from '../storagePaths';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import {
  attachUploadProgressListener,
  createUploadXhrLifecycle,
} from './uploadXhrLifecycle';

const wait = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

const DEFAULT_TIMEOUT_MS = 60000;
